// Helper function to parse a fraction string "num/den"
std::pair<int, int> parseFractionString(const std::string& s) {
    size_t slashPos = s.find('/');
    if (slashPos == std::string::npos) {
        return {std::stoi(s), 1};
    }
    int num = std::stoi(s.substr(0, slashPos));
    int den = std::stoi(s.substr(slashPos + 1));
    return {num, den};
}

// Function to run a single test case
void runTestCase(const std::string& input, const std::string& expected_output) {
    std::cout << "Input: " << input << std::endl;

    size_t starPos = input.find('*');
    std::string frac1_str = input.substr(0, starPos - 1);
    std::string frac2_str = input.substr(starPos + 2);

    std::pair<int, int> p1 = parseFractionString(frac1_str);
    std::pair<int, int> p2 = parseFractionString(frac2_str);

    Fraction f1(p1.first, p1.second);
    Fraction f2(p2.first, p2.second);

    Fraction result = f1 * f2;

    std::cout << "Expected: " << expected_output << std::endl;
    std::cout << "Actual:   ";
    result.print();
    std::cout << std::endl << std::endl;
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "1/2 * 3/4", "3/8" },
        { "2/3 * 6/7", "12/21" },
        { "-1/2 * 1/3", "-1/6" },
        { "5/1 * 2/5", "10/5" },
        { "0/5 * 1/2", "0/10" }
    };

    for (const auto& tc : test_cases) {
        runTestCase(tc.first, tc.second);
    }

    // Demonstrating the zero denominator robustness issue (not part of automated tests, but relevant)
    std::cout << "Robustness Test (Zero Denominator):" << std::endl;
    Fraction invalid_f(5, 0);
    std::cout << "Fraction(5,0) printed: ";
    invalid_f.print();
    std::cout << std::endl << std::endl;

    return 0;
}
